### Phase 6: Story page integration (`src/app/story/[id]/page.tsx`)

**Step 6.1 — New imports** (add to top):
```ts
import { useRef } from 'react';  // add to existing React import
import type { HandoffNote, SessionState } from '@/types/handoff';
import { saveHandoffNote, getHandoffNotes, getLatestHandoffNote, saveSessionState, getSessionState, isResumeCardSnoozed, setResumeCardSnoozed } from '@/lib/handoff';
import { HandoffNoteModal } from '@/components/HandoffNoteModal/HandoffNoteModal';
import { ResumeContextCard } from '@/components/ResumeContextCard/ResumeContextCard';
import { HandoffHistory } from '@/components/HandoffHistory/HandoffHistory';
```

**Step 6.2 — New state + refs** (inside component, after existing useState lines):
```ts
const [showHandoffModal, setShowHandoffModal]   = useState(false);
const [sessionState, setSessionState]           = useState<SessionState | null>(null);
const [latestNote, setLatestNote]               = useState<HandoffNote | null>(null);
const [handoffNotes, setHandoffNotes]           = useState<HandoffNote[]>([]);
const [resumeCardVisible, setResumeCardVisible] = useState(false);
const editorRef = useRef<HTMLTextAreaElement>(null);
```

**Step 6.3 — Load session on mount** (add as new `useEffect`, after existing effects):
```ts
useEffect(() => {
  const session = getSessionState(id);
  const note    = getLatestHandoffNote(id);
  const notes   = getHandoffNotes(id);
  setSessionState(session);
  setLatestNote(note);
  setHandoffNotes(notes);
  if (session && !isResumeCardSnoozed(id)) setResumeCardVisible(true);
}, [id]);
```

**Step 6.4 — Session tracking** (add `onBlur` handler):
```ts
const handleEditorBlur = () => {
  if (!editorRef.current) return;
  saveSessionState(
    id,
    {
      storyId: id,
      lastEditedSceneId: null,   // v1: no scene selection in editor view
      lastEditedSceneTitle: null,
      lastEditorScrollTop: editorRef.current.scrollTop,
      lastEditorCursorOffset: editorRef.current.selectionStart,
      lastHandoffNoteId: latestNote?.id ?? null,
    },
    storyTitle
  );
};
```

**Step 6.5 — Handoff handlers**:
```ts
const handleHandoffSave = (note: HandoffNote) => {
  setLatestNote(note);
  setHandoffNotes(getHandoffNotes(id));
  setShowHandoffModal(false);
};

const handleResumeScene = (sceneId: string | null, scrollTop: number, cursorOffset: number) => {
  setResumeCardVisible(false);
  requestAnimationFrame(() => {
    if (!editorRef.current) return;
    editorRef.current.scrollTop = scrollTop;
    editorRef.current.setSelectionRange(cursorOffset, cursorOffset);
    editorRef.current.focus();
  });
};

const handleResumeSnooze = () => {
  setResumeCardSnoozed(id);
  setResumeCardVisible(false);
};
```

**Step 6.6 — JSX changes**:

1. Add `ref={editorRef}` and `onBlur={handleEditorBlur}` to the `<textarea>`.

2. Add `.editorHeaderActions` row in `.editorHeader` (after title input):
```tsx
<div className={styles.editorHeaderActions}>
  <ViewModeSwitch mode={viewMode} onChange={setViewMode} />
  <SaveStatus saveState={saveState} lastSaved={lastSaved} onRetry={retrySave} />
  <button
    className={styles.endSessionButton}
    onClick={() => setShowHandoffModal(true)}
    aria-label="Save end-session handoff note"
  >
    End session
  </button>
</div>
```
Remove the existing `<ViewModeSwitch>` and `<SaveStatus>` lines from their current position, since they move into this new actions row.

3. Between `.editorMain > .editorHeader` and `.editorCanvas`, insert:
```tsx
{resumeCardVisible && sessionState && (
  <ResumeContextCard
    session={sessionState}
    latestNote={latestNote}
    onResume={handleResumeScene}
    onDismiss={() => setResumeCardVisible(false)}
    onSnooze={handleResumeSnooze}
  />
)}
```

4. Replace the sidebar placeholder content with `<HandoffHistory notes={handoffNotes} />` (keep the outer `.sidebarSection` div and `.sidebarTitle` h3 — just replace `.sidebarPlaceholder` contents).

5. After the entire layout JSX (before the closing `</div>` of `.page`), add:
```tsx
{showHandoffModal && (
  <HandoffNoteModal
    storyId={id}
    activeSceneId={null}
    activeSceneTitle={null}
    onSave={handleHandoffSave}
    onDismiss={() => setShowHandoffModal(false)}
  />
)}
```

**Step 6.7 — CSS additions to `page.module.css`**:

```css
