## Goal

Implement anchored beta-reader comments on shared read-only chapter previews, with a writer feedback panel in the story sidebar and a persistent resolve/reopen workflow. All data stored in localStorage for v1.

## Scope and files

**New files:**
- `src/types/feedback.ts` — ShareLink, FeedbackComment, AnchorTarget types
- `src/lib/feedback.ts` — localStorage CRUD for share links + comments
- `src/app/story/[id]/preview/[token]/page.tsx` — read-only share preview (new route)
- `src/app/story/[id]/preview/[token]/page.module.css`
- `src/components/SharePreviewCard/SharePreviewCard.tsx`
- `src/components/SharePreviewCard/SharePreviewCard.module.css`
- `src/components/FeedbackPanel/FeedbackPanel.tsx`
- `src/components/FeedbackPanel/FeedbackPanel.module.css`
- `src/components/CommentThread/CommentThread.tsx`
- `src/components/CommentThread/CommentThread.module.css`

**Modified files:**
- `src/app/story/[id]/page.tsx` — add "Sharing" and "Feedback" sidebar sections
- `src/app/story/[id]/page.module.css` — no new classes needed (reuse `.sidebarSection`)

## Step-by-step plan

### Phase 1: Types (`src/types/feedback.ts`)

```ts
export interface ShareLink {
  token: string;                  // crypto.randomUUID() slug
  storyId: string;
  storyTitle: string;
  commentsEnabled: boolean;
  createdAt: string;              // ISO
  expiresAt: string | null;       // ISO, null = no expiry
  revoked: boolean;
}

export interface AnchorTarget {
  paragraphIndex: number;         // 0-based index into story content split by \n\n
  paragraphPreview: string;       // first 80 chars of that paragraph at time of comment
}

export interface FeedbackComment {
  id: string;                     // crypto.randomUUID()
  storyId: string;
  token: string;                  // which share link
  readerAlias: string;            // reader-supplied name
  body: string;                   // comment text
  anchor: AnchorTarget | null;    // null = general chapter note
  resolved: boolean;
  followUpPlanned: boolean;       // writer marks for planned revision
  createdAt: string;              // ISO
  resolvedAt: string | null;
}
```

### Phase 2: Feedback lib (`src/lib/feedback.ts`)

localStorage keys:
- `share-links-${storyId}` → `ShareLink[]`
- `feedback-comments-${storyId}` → `FeedbackComment[]`, no cap

```ts
export function getShareLinks(storyId: string): ShareLink[]
export function createShareLink(storyId: string, storyTitle: string, commentsEnabled: boolean): ShareLink
  // token = crypto.randomUUID()
export function revokeShareLink(storyId: string, token: string): void
  // Sets revoked = true (not deleted — preserves historical data)
export function toggleShareLinkComments(storyId: string, token: string, enabled: boolean): void
export function getShareLinkByToken(token: string): ShareLink | null
  // Scans all stories via getStories() → getShareLinks(story.id) for the matching token
  // Returns null if not found or revoked

export function getComments(storyId: string): FeedbackComment[]
  // All comments, newest-first
export function getOpenComments(storyId: string): FeedbackComment[]
export function getCommentsByStatus(storyId: string, resolved: boolean): FeedbackComment[]
export function addComment(storyId: string, comment: Omit<FeedbackComment, 'id' | 'createdAt' | 'resolved' | 'resolvedAt' | 'followUpPlanned'>): FeedbackComment
export function resolveComment(storyId: string, commentId: string): void
export function reopenComment(storyId: string, commentId: string): void
export function toggleFollowUp(storyId: string, commentId: string): void
```

**Anchor paragraph helper:**
```ts
export function getParagraphsFromContent(content: string): string[]
  // content.split(/\n\n+/).filter(p => p.trim())

export function getAnchorPreview(paragraphs: string[], index: number): string
  // paragraphs[index]?.substring(0, 80) ?? ''
