                aria-label={`Comment on paragraph ${idx + 1} (${paraComments.length} comment${paraComments.length === 1 ? '' : 's'})`}
              >
                {paraComments.length > 0 && <span className={styles.markerCount}>{paraComments.length}</span>}
                <span className={styles.markerIcon} aria-hidden="true">💬</span>
              </button>
            )}
            {activeAnchorIdx === idx && shareLink?.commentsEnabled && (
              <CommentThread
                comments={paraComments}
                isWriterView={false}
                onSubmit={(alias, body) => handleSubmitComment(alias, body, idx)}
                alias={readerAlias}
                onAliasChange={setReaderAlias}
