            )}
          </div>
        );
      })}

      {/* General notes section */}
      {shareLink?.commentsEnabled && (
        <div className={styles.generalNotes}>
          <h3 className={styles.sectionTitle}>General notes</h3>
          {comments.filter(c => !c.anchor).map(c => (
            <CommentThread key={c.id} comments={[c]} isWriterView={false} onSubmit={null} alias={readerAlias} onAliasChange={setReaderAlias} />
          ))}
          <CommentThread
            comments={[]}
            isWriterView={false}
            onSubmit={(alias, body) => handleSubmitComment(alias, body, null)}
