        <input
          ref={inputRef}
          type="text"
          role="combobox"
          aria-expanded="true"
          aria-autocomplete="list"
          aria-controls="cmd-results"
          className={styles.input}
          placeholder="Search stories, scenes, actions…"
          value={query}
          onChange={e => { setQuery(e.target.value); setActiveIndex(0); }}
        />
        {query && (
          <button className={styles.clearButton} onClick={() => setQuery('')} aria-label="Clear search">✕</button>
        )}
      </div>

      {/* Results list */}
      <ul id="cmd-results" role="listbox" className={styles.results}>
        {/* render groups with sticky headers */}
