export type SyncStatusValue = 'off' | 'idle' | 'syncing' | 'synced' | 'conflict' | 'failed';

export interface SyncConfig {
  enabled: boolean;
  passphraseSet: boolean;  // passphrase itself NEVER stored
  deviceId: string;        // crypto.randomUUID(), stored per device
  deviceName: string;      // e.g. "MacBook Pro", filled from navigator.userAgent heuristic
  connectedDevices: DeviceEntry[];
  lastSyncAt: string | null;  // ISO
}

export interface DeviceEntry {
  deviceId: string;
  deviceName: string;
  lastSyncAt: string | null;
}

export interface SnapshotEntry {
  id: string;
  storyId: string;
  storyTitle: string;
  syncedAt: string;        // ISO
  deviceId: string;
  deviceName: string;
  encryptedSize: number;   // bytes, for display
}

export interface ConflictState {
